mapper.insert:
/** CmmtInsiderDao.insert */
insert into cmmt_insider (
	 member_id
	,login_id
	,enc_passwd
	,passwd_dt
	,passwd_init
	,member_nm
	,nickname
	,gender
	,dept_nm
	,position_nm
	,authority_id
	,member_st
	,member_st_dt
	,enc_tel_no
	,enc_mobile_no
	,enc_email
	,member_ips
	,refresh_token
	,last_login_dt
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	 #{memberId}
	,#{loginId}
	,#{encPasswd}
	,#{passwdDt}
	,#{passwdInit}
	,#{memberNm}
	,#{nickname}
	,#{gender}
	,#{deptNm}
	,#{positionNm}
	,#{authorityId}
	,#{memberSt}
	,#{memberStDt}
	,#{encTelNo}
	,#{encMobileNo}
	,#{encEmail}
	,#{memberIps}
	,#{refreshToken}
	,#{lastLoginDt}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.update:
/** CmmtInsiderDao.update */
update cmmt_insider set
	 login_id      = #{loginId}
	,enc_passwd    = #{encPasswd}
	,passwd_dt     = #{passwdDt}
	,passwd_init   = #{passwdInit}
	,member_nm     = #{memberNm}
	,nickname      = #{nickname}
	,gender        = #{gender}
	,dept_nm       = #{deptNm}
	,position_nm   = #{positionNm}
	,authority_id  = #{authorityId}
	,member_st     = #{memberSt}
	,member_st_dt  = #{memberStDt}
	,enc_tel_no    = #{encTelNo}
	,enc_mobile_no = #{encMobileNo}
	,enc_email     = #{encEmail}
	,member_ips    = #{memberIps}
	,refresh_token = #{refreshToken}
	,last_login_dt = #{lastLoginDt}
	,creator_id    = #{creatorId}
	,created_dt    = #{createdDt}
	,updater_id    = #{updaterId}
	,updated_dt    = #{updatedDt}
where
	member_id = #{memberId}
